"use strict";(self.webpackChunkskill_doc=self.webpackChunkskill_doc||[]).push([[988],{5955(e){e.exports=JSON.parse('{"id":"frontend-design","name":"frontend-design","description":"Create distinctive, production-grade frontend interfaces with high design quality. Generates creative, polished code and UI design that avoids generic AI aesthetics.","license":"Complete terms in LICENSE.txt","content":"\\n# Frontend Design\\n\\nThis skill guides creation of distinctive, production-grade frontend interfaces that avoid generic \\"AI slop\\" aesthetics.\\n\\n## Design Thinking\\n\\nBefore coding, understand the context and commit to a **BOLD aesthetic direction**:\\n\\n- **Purpose**: What problem does this interface solve? Who uses it?\\n- **Tone**: Pick an extreme \u2014 brutally minimal, maximalist chaos, retro-futuristic, organic/natural, luxury/refined...\\n- **Constraints**: Technical requirements (framework, performance, accessibility)\\n- **Differentiation**: What makes this **UNFORGETTABLE**?\\n\\n## Frontend Aesthetics Guidelines\\n\\n### Typography\\nChoose fonts that are beautiful, unique, and characterful. Avoid Arial, Inter, Roboto. Pair a distinctive display font with a refined body font.\\n\\n### Color & Theme\\nCommit to a cohesive aesthetic. Use CSS variables for consistency. Dominant colors with sharp accents outperform timid, evenly-distributed palettes.\\n\\n### Motion\\nUse animations for micro-interactions. Focus on high-impact moments: one well-orchestrated page load with staggered reveals creates more delight than scattered micro-interactions.\\n\\n### Spatial Composition\\nUnexpected layouts. Asymmetry. Overlap. Diagonal flow. Grid-breaking elements. Generous negative space **OR** controlled density.\\n\\n### Backgrounds & Visual Details\\nCreate atmosphere and depth. Apply gradient meshes, noise textures, geometric patterns, layered transparencies, dramatic shadows.\\n\\n## Implementation Workflow\\n\\n1. **Plan**: Understand purpose, audience, constraints\\n2. **Design Direction**: Commit to a bold aesthetic\\n3. **Build Foundation**: CSS variables, typography, color system\\n4. **Components**: Focused, reusable, animated\\n5. **Polish**: Hover states, transitions, responsive behavior\\n","githubUrl":"https://github.com/cardoso-thiago/skill-doc/blob/main/skills/frontend-design/SKILL.md"}')}}]);